Hongcow Buys a Deck of Cards
Also note that if r_i or b_i >= n, we need to collect tokens no matter what since those costs can't be offset. So, we can assume that r_i, b_i <= n.

Let's only buy tokens when we need them. Note that after buying a card, you will have either 0 red tokens or 0 blue tokens, so our dp state can be described by [mask][which one is zero][how many of the other] The dimensions of this dp table are 2^n * 2 * (n^2) (n^2 because the costs to buy cards is at most n).

See the code for more details on how to update this dp.
 code
```
import java.util.Arrays;
import java.util.Scanner;

public class RedAndBlueCards {
    public static int n;
    public static char[] color;
    public static int[] r,b;
    public static int[] countred, countblue;
    public static void main (String[] args) {
        Scanner in = new Scanner(System.in);
        n = in.nextInt();
        color = new char[n];
        r = new int[n];
        b = new int[n];
        int base = 0;
        int needred = 0, needblue = 0;
        for (int i = 0; i < n; i++) {
            color[i] = in.next().charAt(0);
            r[i] = in.nextInt();
            b[i] = in.nextInt();
            needred += Math.max(0, r[i] - n);
            needblue += Math.max(0, b[i] - n);
            r[i] = Math.min(n, r[i]);
            b[i] = Math.min(n, b[i]);
        }
        base = Math.max(needred, needblue);

        countred = new int[1<<n];
        countblue = new int[1<<n];
        for (int i = 1; i < 1 << n; i++) {
            int lowbit = Integer.numberOfTrailingZeros(i & -i);
            countred[i] = countred[i ^ (1 << lowbit)];
            countblue[i] = countblue[i ^ (1 << lowbit)];
            if (color[lowbit] == 'R') countred[i]++;
            else countblue[i]++;
        }

        dp = new int[2][n*n+1][1<<n];
        for (int[][] x : dp) for (int[] y : x) Arrays.fill(y, -1);

        int ans = base + n;
        if (needred < needblue) {
            ans += solve(0, 0, needblue - needred);
        } else {
            ans += solve(0, 1, needred - needblue);
        }
        System.out.println(ans);
        System.exit(0);
    }

    public static int[][][] dp;
    public static int solve(int mask, int redempty, int other) {
        other = Math.min(other, n*n);
        if (mask == (1<<n)-1) return 0;
        if (dp[redempty][other][mask] != -1) return dp[redempty][other][mask];
        int ret = 1 << 29;
        for (int i = 0; i < n; i++) {
            if (((mask>>i)&1) == 1) continue;
            int pmask = mask | (1 << i);
            int havered = redempty == 1 ? 0 : other;
            int haveblue = redempty == 0 ? 0 : other;
            int cardred = countred[mask], cardblue = countblue[mask];

            int nred = Math.max(0, r[i]-(cardred+havered));
            int nblue = Math.max(0, b[i]-(cardblue+haveblue));
            int needmoves = Math.max(nred, nblue);
            int nextred = havered + needmoves - Math.max(0, r[i] - cardred);
            int nextblue = haveblue + needmoves - Math.max(0, b[i] - cardblue);

            if (nextred == 0) {
                ret = Math.min(ret, needmoves + solve(pmask, 1, nextblue));
            }
            if (nextblue == 0) {
                ret = Math.min(ret, needmoves + solve(pmask, 0, nextred));
            }
        }
        return dp[redempty][other][mask] = ret;
    }
}

```
Hongcow Draws a Circle
First to check if an answer can be arbitrarily large, we can see if there is any red point that is on the convex hull of all our points. So from now on, we can assume the answer is finite.

We can show that the optimal circle must touch a blue point. To see this, consider any optimal circle that doesn't touch a blue point. We can make it slightly bigger so that it does touch one.

So, let's binary search for the answer. However, you have to very careful and notice that the binary search isn't monotonic if we only consider circles touching blue points. However, if we consider circles that touch either a red or blue point, then the binary search is monontonic, so everything works out.

To check if a radius works, we can do a angle sweep around our center point. We have a fixed radius and fixed center, so each other point has at most two angles where it enters and exits the circle as we rotate it about the center point. We can keep track of these events and find an interval where the circle only contains red points.
 code for binary search
```
import java.io.*;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.StringTokenizer;

public class RedAndBluePoints {
    public static double EPS = 1e-9;
    public static int PENALTY = 1000000;
    public static int n,m;
    public static long[] x, y;
    public static double[][] d;
    public static void main (String[] args) {
        InputReader in = new InputReader(System.in);
        PrintWriter out = new PrintWriter(System.out, true);

        n = in.nextInt();
        m = in.nextInt();
        x = new long[n+m];
        y = new long[n+m];
        d = new double[n+m][n+m];
        Point[] ps = new Point[n+m];
        for (int i = 0; i < n+m; i++) {
            x[i] = in.nextInt();
            y[i] = in.nextInt();
            ps[i] = new Point(x[i], y[i]);
        }
        ps = convexHull(ps);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < ps.length; j++) {
                if (onSegment(ps[j], ps[(j+1)%ps.length], new Point(x[i],y[i]))) {
                    out.println(-1);
                    out.close();
                    System.exit(0);
                }
            }
        }


        for (int i = 0; i < n+m; i++) {
            for (int j = 0; j < n+m; j++) {
                d[i][j] = (x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j]);
            }
        }

        double lower = 0;
        for (int startpoint = 0; startpoint < n+m; startpoint++) {
            if (!ok(startpoint, lower)) continue;
            double add = 20;
            int iter = 30;
            while (ok(startpoint, lower+2*add)) {
                add *= 2;
                iter++;
            }
            double lo = lower;
            double hi = lower+2*add;
            while (hi - lo > 1e-8 && iter-->0) {
                double mid = (lo + hi) / 2.0;
                if (ok(startpoint, mid)) lo = mid;
                else hi = mid;
            }
            lower = lo;
        }
        out.printf("%.10f\n", lower);
    }

    public static boolean ok(int center, double rad) {
        ArrayList<State> w = new ArrayList<>();
        int cur = center < n ? 1 : 0;
        for (int j = 0; j < n+m; j++) {
            if (j == center) continue;
            double reach = 2 * rad;
            if (reach * reach < d[center][j] + EPS) continue;

            double[] q = getAngles(center, j, rad);
            int add = j < n ? 1 : -PENALTY;
            if (q[1] < q[0]) cur += add;
            w.add(new State(q[0] - EPS, add));
            w.add(new State(q[1] + EPS, -add));
        }
        Collections.sort(w);
        int res = cur;
        for (State s : w) {
            cur += s.inc;
            res = Math.max(res, cur);
        }
        return res >= 1;
    }

    // returns two angles tangent to point i1 and point i2 with radius.
    public static double[] getAngles(int i1, int i2, double rad) {
        double D = d[i1][i2];
        double c = D/2.0;
        double b = Math.sqrt(D*rad*rad-c*c);
        double nx = (x[i2] - x[i1]) / D, ny = (y[i2] - y[i1]) / D;
        double bx = -ny * b, by = nx * b;
        double ax = nx * c, ay = ny * c;

        return new double[] {
                Math.atan2(ay - by, ax - bx),
                Math.atan2(ay + by, ax + bx),
        };
    }

    public static class Point {
        public final long x, y;

        public Point(long x, long y) {
            this.x = x;
            this.y = y;
        }
    }
    public static Point[] convexHull(Point[] p) {
        int n = p.length;
        if (n <= 1)
            return p;
        Arrays.sort(p, (a, b) -> Long.compare(a.x, b.x) != 0 ? Long.compare(a.x, b.x) : Long.compare(a.y, b.y));
        Point[] h = new Point[n * 2];
        int cnt = 0;
        for (int i = 0; i < n; h[cnt++] = p[i++])
            while (cnt > 1 && cross(h[cnt - 2], h[cnt - 1], p[i]) >= 0)
                --cnt;
        for (int i = n - 2, t = cnt; i >= 0; h[cnt++] = p[i--])
            while (cnt > t && cross(h[cnt - 2], h[cnt - 1], p[i]) >= 0)
                --cnt;
        return Arrays.copyOf(h, cnt - 1 - (h[0].x == h[1].x && h[0].y == h[1].y ? 1 : 0));
    }

    static long cross(Point a, Point b, Point c) {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    }

    public static boolean onSegment(Point a, Point b, Point c) {
        // does c lie on segment ab
        return c.x >= Math.min(a.x, b.x) && c.x <= Math.max(a.x, b.x) &&
                c.y >= Math.min(a.y, b.y) && c.y <= Math.max(a.y, b.y) &&
                (c.x - a.x) * (c.y - b.y) == (c.x - b.x) * (c.x - a.y);
    }


    static class State implements Comparable<State> {
        public double angle;
        public int inc;
        public State (double angle, int inc) {
            this.angle = angle;
            this.inc = inc;
        }

        public int compareTo(State other) {
            if (angle < other.angle) return -1;
            if (angle > other.angle) return 1;
            return 0;
        }
    }

    static class InputReader {
        public BufferedReader reader;
        public StringTokenizer tokenizer;

        public InputReader(InputStream stream) {
            reader = new BufferedReader(new InputStreamReader(stream), 32768);
            tokenizer = null;
        }

        public String next() {
            while (tokenizer == null || !tokenizer.hasMoreTokens()) {
                try {
                    tokenizer = new StringTokenizer(reader.readLine());
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            }
            return tokenizer.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }
    }
}

```

For the inversion solution, let's fix the blue point that our circle touches. Then, let's take the inversion around this point (i.e. https://en.wikipedia.org/wiki/Inversive_geometry). Now, circles that pass through our center points become lines, and the interior of those circles are in the halfplane not containing the center point. The radius of the circle is inversely proportional to the distance between our center point to the line after inversion.

So, we can say we want to solve the following problem after inversion. Find the closest line that contains no blue points in the halfplane facing away from our center point and at least one red point. We can notice that we only need to check lines that contain a blue point on the convex hull after inversion.

To make implementation easier, you can make the additional observation that the sum of all convex hull sizes will be linear through the process of the algorithm. Some intuition behind this observation is that only adjacent nodes in a delaunay triangluation can appear on the convex hull after inversion, so the sum is bounded by the number of edges in such a triangulation (of course, we do not need to explicitly find the triangulation).
 code for inversion
```
#pragma comment(linker, "/STACK:1000000000")
#include <cstdio>
#include <cmath>
#include <cstdlib>
#include <cassert>
#include <ctime>
#include <cstring>
#include <string>
#include <set>
#include <map>
#include <vector>
#include <list>
#include <deque>
#include <queue>
#include <sstream>
#include <iostream>
#include <algorithm>

using namespace std;

#define pb push_back
#define mp make_pair
#define fs first
#define sc second
#define double long double

const double pi = acos(-1.0);
const double eps1 = 1e-7;
const double eps2 = 1e-14;

double sqr(double x) {
    return x * x; 
}

struct pt {
	double x, y;

    pt(double x_ = 0.0, double y_ = 0.0) : x(x_), y(y_) {}
};

pt operator + (const pt& a, const pt& b) {
	return pt(a.x + b.x, a.y + b.y);
}

pt operator - (const pt& a, const pt& b) {
	return pt(a.x - b.x, a.y - b.y);
}

pt operator * (const pt& a, double k) {
	return pt(a.x * k, a.y * k);
}

struct line {
	double a, b, c;
	line(double a_ = 1.0, double b_ = 0.0, double c_ = 0.0): a(a_), b(b_), c(c_) {
		norm();
    }

	line(const pt& p1, const pt& p2) {
		a = p2.y - p1.y;
		b = p1.x - p2.x;
		c = -a * p1.x - b * p1.y;

		norm();
	}

	void norm() {
		double k = sqrt(sqr(a) + sqr(b));
		a /= k;
		b /= k;
		c /= k;
	}

	double dist(const pt& p) const {
		return a * p.x + b * p.y + c;
	}
};
bool cmp (pt a, pt b) {
	return (a.x < b.x) || (a.x == b.x && a.y < b.y);
}

bool cw (pt a, pt b, pt c) {
	return a.x*(b.y-c.y)+b.x*(c.y-a.y)+c.x*(a.y-b.y) < -eps2;
}

bool ccw (pt a, pt b, pt c) {
	return a.x*(b.y-c.y)+b.x*(c.y-a.y)+c.x*(a.y-b.y) > eps2;
}

void convex_hull (vector<pt> & a) {
	if (a.size() == 1)  return;
    if (a.size() == 2) return;
	sort (a.begin(), a.end(), &cmp);
	pt p1 = a[0],  p2 = a.back();
	vector<pt> up, down;
	up.push_back (p1);
	down.push_back (p1);
	for (size_t i=1; i<a.size(); ++i) {
		if (i==a.size()-1 || cw (p1, a[i], p2)) {
			while (up.size()>=2 && !cw (up[up.size()-2], up[up.size()-1], a[i]))
				up.pop_back();
			up.push_back (a[i]);
		}
		if (i==a.size()-1 || ccw (p1, a[i], p2)) {
			while (down.size()>=2 && !ccw (down[down.size()-2], down[down.size()-1], a[i]))
				down.pop_back();
			down.push_back (a[i]);
		}
	}
	a.clear();
	for (size_t i=0; i<up.size(); ++i)
		a.push_back (up[i]);
	for (size_t i=down.size()-2; i>0; --i)
		a.push_back (down[i]);
}

int sign(double x) {
    if (fabs(x) < eps2)
        return 0;
    if (x > 0)
        return 1;
    return -1;
}

int main() {
    //freopen("input.txt", "r", stdin);
    //freopen("output.txt", "w", stdout);

    int n, m;

    cin >> n >> m;

    vector <pt> red(n), blue(m);
    for (int i = 0; i < n; i++) {
        cin >> red[i].x >> red[i].y;
    }

    for (int i = 0; i < m; i++) {
        cin >> blue[i].x >> blue[i].y;
    }

    if (m == 1) {
        cout << -1 << endl;
        return 0;
    }
    vector <pt> cvx_blue = blue;
    convex_hull(cvx_blue);
    int k = cvx_blue.size();

    for (int i = 0; i < n; i++) {
        bool flag = true;
        for (int j = 0; j < k; j++) {
            line hl(cvx_blue[j % k], cvx_blue[(j + 1) % k]);
            if (hl.dist(red[i]) > eps1) {
               flag = false;    
            }
        }

        if (flag) { 
            cout << -1 << endl;

            return 0;
        }

    }


    double ans = 0.0;

    for (int i = 0; i < m; i++) {
        vector <pt> new_blue;
        for (int j = 0; j < i; j++) {
            new_blue.pb(blue[j] - blue[i]);
            double d = sqr(new_blue.back().x) + sqr(new_blue.back().y);
            new_blue.back().x /= d;
            new_blue.back().y /= d;
        }

        new_blue.pb(pt(0.0, 0.0));

        for (int j = i + 1; j < m; j++) {
            new_blue.pb(blue[j] - blue[i]);
            double d = sqr(new_blue.back().x) + sqr(new_blue.back().y);
            new_blue.back().x /= d;
            new_blue.back().y /= d;
        }

        vector <pt> new_red;
        for (int j = 0; j < n; j++) {
            new_red.pb(red[j] - blue[i]);
            double d = sqr(new_red.back().x) + sqr(new_red.back().y);
            new_red.back().x /= d;
            new_red.back().y /= d;        
        }

        convex_hull(new_blue);

        int k = new_blue.size();
        int p = new_red.size();

        for (int j = 0; j < k; j++) {
            bool flag = false;
            line hl(new_blue[j], new_blue[(j + 1) % k]);

            for (int q = 0; q < p; q++) {
                if (hl.dist(new_red[q]) < eps2)
                    flag = true;            
            }            

            if (flag) {
                if (abs(hl.dist(pt(0.0, 0.0))) < eps2) {
                    cout << -1 << endl;

                    return 0;
                }
