            ans += i - front;
        }

        out.println(ans);
        out.close();
        System.exit(0);
    }

    public static boolean isGood(int from, int to) {
        if (from > to) return true;
        int numnodes = len[to] - len[from - 1];
        ArrayList<Integer>[] graph = new ArrayList[numnodes+1];
        for (int i = 0; i <= numnodes; i++) graph[i] = new ArrayList<>();
        for (int startword = from; startword <= to; startword++) {
            graph[numnodes].add(len[startword-1] - len[from-1]);
            StringBuilder sb = new StringBuilder();
            sb.append(s[startword]);
            sb.append("$");
            for (int k = from; k <= to; k++) {
                if (k == startword) continue;
                sb.append(s[k]);
                sb.append("#");
            }
            int[] z = zz(sb.toString().toCharArray());

            int curchar = 0;
            for (int i = 1; i < s[startword].length(); i++) {
                if (z[i] + i >= s[startword].length()) {
                    graph[i + len[startword-1] - len[from -1]].add(z[i] + len[startword-1] - len[from-1]);
                }
            }
            int curword = startword == from ? (from+1) : from;
            for (int i = s[startword].length()+1; i+1 < z.length; i++) {
                if (sb.charAt(i) == '#') {
                    i++;
                    curword++;
                    if (curword == startword) curword++;
                    curchar = 0;
                }

                int curnode = curchar + len[curword-1] - len[from-1];
                if (z[i] + curchar >= s[curword].length()) {
                    if (z[i] == s[startword].length()) {
                        if (curchar != 0) graph[curnode].add(numnodes);
                    } else {
                        graph[curnode].add(z[i] + len[startword-1] - len[from-1]);
                    }
                } else if (z[i] == s[startword].length()) {
                    graph[curnode].add(curnode + z[i]);
                }
                curchar++;
            }

        }
        return isDAG(graph);
    }

    public static int[] zz(char[] let) {
        int N = let.length;
        int[] z = new int[N];
        int L = 0, R = 0;
        for (int i = 1; i < N; i++) {
            if (i > R) {
                L = R = i;
                while (R < N && let[R - L] == let[R])
                    R++;
                z[i] = R - L;
                R--;
            } else {
                int k = i - L;
                if (z[k] < R - i + 1)
                    z[i] = z[k];
                else {
                    L = i;
                    while (R < N && let[R - L] == let[R])
                        R++;
                    z[i] = R - L;
                    R--;
                }
            }
        }
        z[0] = N;
        return z;
    }

    private static boolean isDAG(ArrayList<Integer>[] graph) {
        int n = graph.length;
        int[] indeg = new int[n];
        for (int i = 0; i < n; i++) for (int x : graph[i]) indeg[x]++;
        int[] queue = new int[n];
        int front = 0, back = 0, idx = 0;

        for (int i = 0; i < indeg.length; i++)
            if (indeg[i] == 0)
                queue[back++] = i;

        while (front != back) {
            int node = queue[front++];
            for (int next : graph[node]) {
                if (--indeg[next] == 0) {
                    queue[back++] = next;
                }
            }
        }

        return front == n;
    }

