            w.add(new State(q[0] - EPS, add));
            w.add(new State(q[1] + EPS, -add));
        }
        Collections.sort(w);
        int res = cur;
        for (State s : w) {
            cur += s.inc;
            res = Math.max(res, cur);
        }
        return res >= 1;
