    // returns two angles tangent to point i1 and point i2 with radius.
    public static double[] getAngles(int i1, int i2, double rad) {
        double D = d[i1][i2];
        double c = D/2.0;
        double b = Math.sqrt(D*rad*rad-c*c);
        double nx = (x[i2] - x[i1]) / D, ny = (y[i2] - y[i1]) / D;
        double bx = -ny * b, by = nx * b;
        double ax = nx * c, ay = ny * c;

        return new double[] {
                Math.atan2(ay - by, ax - bx),
                Math.atan2(ay + by, ax + bx),
        };
