const double eps2 = 1e-14;

double sqr(double x) {
    return x * x; 
}

struct pt {
	double x, y;

    pt(double x_ = 0.0, double y_ = 0.0) : x(x_), y(y_) {}
};

pt operator + (const pt& a, const pt& b) {
	return pt(a.x + b.x, a.y + b.y);
}

pt operator - (const pt& a, const pt& b) {
	return pt(a.x - b.x, a.y - b.y);
}

pt operator * (const pt& a, double k) {
	return pt(a.x * k, a.y * k);
}

struct line {
	double a, b, c;
	line(double a_ = 1.0, double b_ = 0.0, double c_ = 0.0): a(a_), b(b_), c(c_) {
		norm();
    }

	line(const pt& p1, const pt& p2) {
		a = p2.y - p1.y;
		b = p1.x - p2.x;
		c = -a * p1.x - b * p1.y;

		norm();
	}

	void norm() {
		double k = sqrt(sqr(a) + sqr(b));
		a /= k;
		b /= k;
		c /= k;
	}

	double dist(const pt& p) const {
		return a * p.x + b * p.y + c;
	}
};
bool cmp (pt a, pt b) {
	return (a.x < b.x) || (a.x == b.x && a.y < b.y);
}

bool cw (pt a, pt b, pt c) {
	return a.x*(b.y-c.y)+b.x*(c.y-a.y)+c.x*(a.y-b.y) < -eps2;
}

bool ccw (pt a, pt b, pt c) {
	return a.x*(b.y-c.y)+b.x*(c.y-a.y)+c.x*(a.y-b.y) > eps2;
}

void convex_hull (vector<pt> & a) {
	if (a.size() == 1)  return;
    if (a.size() == 2) return;
	sort (a.begin(), a.end(), &cmp);
	pt p1 = a[0],  p2 = a.back();
	vector<pt> up, down;
	up.push_back (p1);
	down.push_back (p1);
	for (size_t i=1; i<a.size(); ++i) {
		if (i==a.size()-1 || cw (p1, a[i], p2)) {
			while (up.size()>=2 && !cw (up[up.size()-2], up[up.size()-1], a[i]))
				up.pop_back();
			up.push_back (a[i]);
		}
		if (i==a.size()-1 || ccw (p1, a[i], p2)) {
			while (down.size()>=2 && !ccw (down[down.size()-2], down[down.size()-1], a[i]))
				down.pop_back();
			down.push_back (a[i]);
		}
	}
	a.clear();
	for (size_t i=0; i<up.size(); ++i)
		a.push_back (up[i]);
	for (size_t i=down.size()-2; i>0; --i)
		a.push_back (down[i]);
}

int sign(double x) {
    if (fabs(x) < eps2)
        return 0;
    if (x > 0)
        return 1;
    return -1;
}

